form:Form.form:Scripts:
		function ClearEmpresa()
{
	Ctrl("oi_empresa").SetCValue("");                     
	ClearPuesto();
}

function ClearPuesto()
{                     
	Ctrl("oi_puesto").SetCValue("");
	ClearPosicion();
}

function ClearPosicion()
{                     
	Ctrl("oi_posicion").SetCValue("");
}

 function OnLoad()
{                              
	if  (Ctrl("Estado").GetXValue()=="Sin Errores") 
	{ 	CtrlEnabled("btn_logTCO",false	);          }
	else
	{ 	CtrlEnabled("btn_logTCO",true);              }
}                            

function EJECUTAR_CLICK()
{                             
	if (Ctrl("oi_empresa").GetXValue()=="") { alert("La Empresa es Requerida."); return false; }      
	if (Ctrl("oi_aniomes").GetXValue()=="") { alert("Mes/Año es Requerido."); return false; }

	if (!Ctrl("main").Validate()) return false;

	var mdx = " with ";
var ColNameAcum= "[Measures].[Acumulado al " + Ctrl("oi_aniomes").GetCValue() +  "] ";
var NameAño =  Ctrl("oi_aniomes").GetCValue().split("/")[1] ;
var ColNameAño = "[Measures].[Total " + NameAño +  "] ";

mdx += "  member " + ColNameAcum + " as 'Sum({([Tiempo].[Todas las fechas].[" + NameAño  + "].[01/" + NameAño  + "]" ;
mdx += " : " + "[Tiempo].[Todas las fechas].[" + NameAño  + "].[" + Ctrl("oi_aniomes").GetCValue() + "])}, [Measures].[TotPagado])'  " ; 
mdx += "  member " + ColNameAño + " as '[Measures].[TotPagado]'" ;
mdx += " select {" + ColNameAño + "," + ColNameAcum +"} ON COLUMNS " ;    






	if(Ctrl("oi_empresa").GetText(1)!="")
		{mdx += ", NON EMPTY Hierarchize(Union([Estructura].[Todo las Estructuras].[" ;
		mdx +=  Ctrl("oi_empresa").GetText(1) + "].Children, [Estructura].[Todo las Estructuras].[" ;
		mdx +=  Ctrl("oi_empresa").GetText(1) + "].Children  )) ON ROWS" ;
		 }


	else
	{
		mdx += ", ([Grupos Sueldos].[Todos los Grupos Sueldos] , [Measures].[Horas]), DESC) ON ROWS ";    

		}

	mdx += " from [SUELDOS]  ";

	var where = "";

	if(Ctrl("oi_empresa").GetText(1)!="")
		where += "[Empresas].[" + Ctrl("oi_empresa").GetText(1) + "],";


	if(where!="")
	{                   
		mdx += "where (" + where.substr(0, where.length-1) + ")";
	}




  //alert(mdx);

	Ctrl("mdx").SetXValue(mdx);

	Ctrl("main").DoEvent("EJECUTAR_CLICK");
	return true;
}
function showLogTCO()
{
	openNewFlowWait("NucleusRH.Base.Indicadores.logTCO.flow","initialize","<param modulo=\"Sueldos\" />",new ObjtectResult(),"L");
}

function ObjtectResult()
{        
	this.processResult= function(xmlin){}
}
